          )}

          {activeTab === 'settings' && (
            <div className="max-w-xl bg-white p-8 rounded-[2rem] shadow-sm border space-y-6 mx-auto"><h3 className="font-black italic uppercase text-lg border-b pb-4">Global Config</h3><div className="space-y-4"><div><label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Deposit UPI ID</label><input type="text" value={appSettings.upi_id} onChange={e => setAppSettings({...appSettings, upi_id: e.target.value})} className="w-full bg-gray-50 border p-4 rounded-2xl font-mono" /></div><div><label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Support Telegram Channel</label><input type="text" value={appSettings.telegram_support_link} onChange={e => setAppSettings({...appSettings, telegram_support_link: e.target.value})} className="w-full bg-gray-50 border p-4 rounded-2xl font-mono" /></div><div className="grid grid-cols-2 gap-4"><div><label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Ref Deposit %</label><input type="number" value={appSettings.referral_deposit_bonus_percent} onChange={e => setAppSettings({...appSettings, referral_deposit_bonus_percent: Number(e.target.value)})} className="w-full bg-gray-50 border p-4 rounded-2xl font-black" /></div><div><label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Ref Loss %</label><input type="number" value={appSettings.referral_bet_loss_bonus_percent} onChange={e => setAppSettings({...appSettings, referral_bet_loss_bonus_percent: Number(e.target.value)})} className="w-full bg-gray-50 border p-4 rounded-2xl font-black" /></div></div><button onClick={handleSaveSettings} className="w-full bg-red-600 text-white font-black py-5 rounded-2xl uppercase tracking-[0.2em] shadow-lg">Save Changes</button></div></div>
          )}
        </main>
      </div>
    </div>
  );
